import{_ as e,a as t,b as i,c as l}from"./chunks/wizard-step6.CcFfa22f.js";import{_ as o,o as r,c as s,ag as n}from"./chunks/framework.BqfgOMAh.js";const x=JSON.parse('{"title":"快速入门","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/getting-started.md","filePath":"zh/guide/getting-started.md"}'),d={name:"zh/guide/getting-started.md"};function h(c,a,p,u,g,m){return r(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="快速入门" tabindex="-1">快速入门 <a class="header-anchor" href="#快速入门" aria-label="Permalink to &quot;快速入门&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">5 分钟快速上手 NexusFlow</p><p>本指南将帮助你完成安装、配置，并进行第一次 AI 对话。</p></div><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><p>在开始之前，请确认你的环境满足以下要求：</p><table tabindex="0"><thead><tr><th>项目</th><th>要求</th></tr></thead><tbody><tr><td>操作系统</td><td>Windows 10 / 11</td></tr><tr><td>虚幻引擎</td><td>Unreal Engine 5.6 / 5.7</td></tr><tr><td>LLM API Key</td><td>OpenAI / Anthropic / Google Gemini / DeepSeek / 智谱 GLM / MiniMax / 通义千问 / Kimi 任选其一</td></tr></tbody></table><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><ol><li>从 <a href="https://github.com/maxzhao/NexusFlow/releases" target="_blank" rel="noreferrer">GitHub Releases</a> 下载最新安装包（<code>.exe</code>）</li><li>运行安装程序，完成 NexusFlow 主程序安装</li><li>从 <a href="https://www.fab.com/" target="_blank" rel="noreferrer">Fab.com</a> 购买并安装 UE 插件（详见 <a href="./installation">安装步骤</a>）</li></ol><h2 id="首次运行向导" tabindex="-1">首次运行向导 <a class="header-anchor" href="#首次运行向导" aria-label="Permalink to &quot;首次运行向导&quot;">​</a></h2><p>首次启动 NexusFlow 后，点击屏幕上的悬浮球，将自动进入引导向导。向导共 6 步，帮助你完成所有必要配置：</p><h3 id="第-1-步-欢迎" tabindex="-1">第 1 步：欢迎 <a class="header-anchor" href="#第-1-步-欢迎" aria-label="Permalink to &quot;第 1 步：欢迎&quot;">​</a></h3><p><img src="'+e+'" alt="首次运行向导 — 欢迎"></p><p>简要介绍 NexusFlow 的功能。你可以点击「开始配置」继续，或点击「跳过」直接进入应用。</p><h3 id="第-2-步-配置-ai-模型" tabindex="-1">第 2 步：配置 AI 模型 <a class="header-anchor" href="#第-2-步-配置-ai-模型" aria-label="Permalink to &quot;第 2 步：配置 AI 模型&quot;">​</a></h3><p><img src="'+t+'" alt="首次运行向导 — 配置 AI 模型"></p><p>这是最关键的一步——你需要至少添加一个 AI 模型才能使用对话功能。</p><ol><li>选择 <strong>Provider</strong>（模型提供商）：OpenAI、Anthropic、Google Gemini、DeepSeek、智谱 GLM、MiniMax、通义千问、Kimi 或 Custom</li><li>填写 <strong>模型名称</strong>（自定义，用于在列表中显示）</li><li>填写 <strong>API Key</strong>，或填写环境变量引用，例如 <code>${OPENAI_API_KEY}</code></li><li>填写 <strong>模型标识</strong>（如 <code>gpt-5.4</code>、<code>claude-opus-4-6</code>）</li><li>可选调整 Temperature 和 Max Tokens</li><li>点击保存</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果选择 Custom Provider，还需要填写 API 地址并选择通讯协议（OpenAI Compatible / OpenAI Responses API / Anthropic Messages API / Google Gemini API）。使用环境变量引用时，真实 API Key 由后端运行时读取，应用配置中只保存 <code>${ENV_NAME}</code>。</p></div><h3 id="第-3-步-ue-插件检查" tabindex="-1">第 3 步：UE 插件检查 <a class="header-anchor" href="#第-3-步-ue-插件检查" aria-label="Permalink to &quot;第 3 步：UE 插件检查&quot;">​</a></h3><p><img src="'+i+'" alt="首次运行向导 — UE 插件检查"></p><p>向导会自动检测你的电脑上是否已安装 Unreal Engine，以及 NexusFlow 插件是否已正确安装。</p><ul><li>✅ 检测到插件：可以直接继续</li><li>❌ 未检测到插件：请参考 <a href="./installation#安装-ue-插件">安装步骤</a> 手动安装</li></ul><h3 id="第-4-步-匿名分析" tabindex="-1">第 4 步：匿名分析 <a class="header-anchor" href="#第-4-步-匿名分析" aria-label="Permalink to &quot;第 4 步：匿名分析&quot;">​</a></h3><p>选择是否允许匿名使用数据收集。这些数据仅用于改进产品，不包含任何个人信息。你可以随时在设置中更改此选项。</p><h3 id="第-5-步-功能介绍" tabindex="-1">第 5 步：功能介绍 <a class="header-anchor" href="#第-5-步-功能介绍" aria-label="Permalink to &quot;第 5 步：功能介绍&quot;">​</a></h3><p>快速了解 NexusFlow 的三个核心功能：</p><ul><li><strong>悬浮球</strong>：桌面上的快速入口，点击即可打开 AI 对话</li><li><strong>AI 对话侧边栏</strong>：与 AI 交流的主界面，支持浮动和停靠模式</li><li><strong>UE 快速菜单</strong>：4 个入口、17 项 AI 操作，覆盖右键菜单和工具栏</li></ul><h3 id="第-6-步-完成" tabindex="-1">第 6 步：完成 <a class="header-anchor" href="#第-6-步-完成" aria-label="Permalink to &quot;第 6 步：完成&quot;">​</a></h3><p><img src="'+l+'" alt="首次运行向导 — 设置完成"></p><p>一切就绪！点击「开始使用」进入 AI 对话界面。</p><div class="info custom-block"><p class="custom-block-title">键盘快捷操作</p><p>在向导中，按 <code>Enter</code> 进入下一步，按 <code>Escape</code> 跳过向导。</p></div><h2 id="ue-插件设置弹窗" tabindex="-1">UE 插件设置弹窗 <a class="header-anchor" href="#ue-插件设置弹窗" aria-label="Permalink to &quot;UE 插件设置弹窗&quot;">​</a></h2><p>首次启动 UE 编辑器（已安装 NexusFlow 插件）时，你可能会看到一个 <strong>NexusFlow Setup</strong> 对话框。这是正常现象——插件会自动检测桌面应用是否安装、Embedding 模型是否就绪。</p><ul><li>如果一切正常，不会弹出对话框</li><li>如果有缺失项，可以点击 <strong>Later</strong> 关闭，稍后再配置</li><li>详见 <a href="./installation#ue-插件首次启动">安装步骤 — UE 插件首次启动</a></li></ul><h2 id="第一次对话" tabindex="-1">第一次对话 <a class="header-anchor" href="#第一次对话" aria-label="Permalink to &quot;第一次对话&quot;">​</a></h2><p>完成向导后，你就可以开始使用 NexusFlow 了：</p><ol><li><strong>启动 NexusFlow</strong> — 桌面上出现悬浮球（蓝紫色渐变圆球）</li><li><strong>启动 UE 编辑器</strong> — 确保 NexusFlow 插件已启用</li><li><strong>等待连接</strong> — 侧边栏底部状态栏从红色变为绿色，显示项目名称和 UE 版本</li><li><strong>打开蓝图</strong> — 在 UE 中打开你想要操作的蓝图</li><li><strong>点击悬浮球</strong> — 打开 AI 对话侧边栏</li><li><strong>输入消息</strong> — 例如输入「解释一下这个蓝图的功能」</li></ol><p>AI 会自动读取你当前打开的蓝图信息，分析后给出回复。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>请确保在对话前 UE 已连接成功（底部状态栏显示绿色圆点）。如果未连接，AI 将无法操作蓝图。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./ai-chat">AI 对话</a> — 深入了解对话界面的功能</li><li><a href="./blueprint-operations">蓝图操作</a> — 常用对话示例和技巧</li><li><a href="./settings">设置说明</a> — 自定义 NexusFlow 的各项配置</li><li><a href="./installation">安装步骤</a> — 查看详细的安装指南</li></ul>',40)])])}const _=o(d,[["render",h]]);export{x as __pageData,_ as default};
